import { useEffect, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { matchesAPI, teamsAPI } from '../api';

const STATUS_COLORS = {
  upcoming: 'bg-blue-100 text-blue-700',
  completed: 'bg-green-100 text-green-700',
  cancelled: 'bg-red-100 text-red-700',
};

export default function Matches() {
  const [matches, setMatches] = useState([]);
  const [teams, setTeams] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [searchParams] = useSearchParams();
  const filterTeamId = searchParams.get('team_id');

  const defaultForm = { team_id: filterTeamId || '', match_number: '', opponent: '', match_date: '', venue: '' };
  const [form, setForm] = useState(defaultForm);

  const load = () =>
    Promise.all([matchesAPI.getAll(filterTeamId), teamsAPI.getAll()])
      .then(([m, t]) => { setMatches(m); setTeams(t); setLoading(false); });

  useEffect(() => { load(); }, [filterTeamId]);

  const submit = async (e) => {
    e.preventDefault();
    await matchesAPI.create(form);
    setForm(defaultForm); setShowForm(false);
    load();
  };

  const deleteMatch = async (id) => {
    if (!window.confirm('Delete this match and all its data?')) return;
    await matchesAPI.delete(id);
    load();
  };

  if (loading) return <div className="flex justify-center py-20 text-emerald-700/70">Loading...</div>;

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <h1 className="title-xl">Matches</h1>
        <button onClick={() => setShowForm(true)} disabled={teams.length === 0}
          className="btn-primary px-4 py-2 text-sm disabled:opacity-50 disabled:cursor-not-allowed">
          + New Match
        </button>
      </div>

      {teams.length === 0 && (
        <div className="panel-soft p-4 text-sm text-amber-700">
          ⚠️ You need to <Link to="/teams" className="underline font-medium">create a team</Link> before adding matches.
        </div>
      )}

      {showForm && (
        <div className="panel p-5 fade-in">
          <h2 className="font-semibold mb-4 text-emerald-900">New Match</h2>
          <form onSubmit={submit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm text-emerald-900/80 mb-1">Team *</label>
              <select value={form.team_id} onChange={e => setForm(f => ({ ...f, team_id: e.target.value }))} required
                className="w-full field text-sm">
                <option value="">Select team...</option>
                {teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm text-emerald-900/80 mb-1">Match Number *</label>
              <input type="number" value={form.match_number} onChange={e => setForm(f => ({ ...f, match_number: e.target.value }))} required min="1"
                className="w-full field text-sm"
                placeholder="e.g. 1" />
            </div>
            <div>
              <label className="block text-sm text-emerald-900/80 mb-1">Opponent *</label>
              <input value={form.opponent} onChange={e => setForm(f => ({ ...f, opponent: e.target.value }))} required
                className="w-full field text-sm"
                placeholder="e.g. Team Beta" />
            </div>
            <div>
              <label className="block text-sm text-emerald-900/80 mb-1">Match Date *</label>
              <input type="date" value={form.match_date} onChange={e => setForm(f => ({ ...f, match_date: e.target.value }))} required
                className="w-full field text-sm" />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm text-emerald-900/80 mb-1">Venue</label>
              <input value={form.venue} onChange={e => setForm(f => ({ ...f, venue: e.target.value }))}
                className="w-full field text-sm"
                placeholder="e.g. City Cricket Ground" />
            </div>
            <div className="md:col-span-2 flex gap-3">
              <button type="submit" className="btn-primary px-5 py-2 text-sm">Create Match</button>
              <button type="button" onClick={() => setShowForm(false)} className="btn-muted px-4 py-2 text-sm">Cancel</button>
            </div>
          </form>
        </div>
      )}

      {matches.length === 0 ? (
        <div className="panel text-center py-16 text-emerald-800/55">
          <p className="text-5xl mb-3">🏆</p>
          <p>No matches yet. Create your first match!</p>
        </div>
      ) : (
        <div className="space-y-3">
          {matches.map(match => (
            <div key={match.id} className="panel hover:-translate-y-0.5 transition-all duration-200">
              <div className="p-5 flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-3 flex-wrap">
                    <Link to={`/matches/${match.id}`} className="font-bold text-emerald-950 text-lg hover:text-emerald-700 hover:underline">
                      Match #{match.match_number} — vs {match.opponent}
                    </Link>
                    <span className={`px-2.5 py-0.5 rounded-full text-xs font-medium ${STATUS_COLORS[match.status]}`}>{match.status}</span>
                  </div>
                  <div className="mt-2 flex flex-wrap gap-4 text-sm text-emerald-900/70">
                    <span>👥 {match.team_name}</span>
                    <span>📅 {new Date(match.match_date).toLocaleDateString()}</span>
                    {match.venue && <span>📍 {match.venue}</span>}
                    <span>✅ <strong className="text-emerald-700">{match.attended_count}</strong> attended • ❌ <strong className="text-rose-600">{match.not_attended_count}</strong> absent</span>
                  </div>
                </div>
                <div className="flex gap-2 ml-4">
                  <Link to={`/matches/${match.id}`} className="bg-emerald-50 hover:bg-emerald-100 text-emerald-700 px-3 py-1.5 rounded-lg text-sm font-medium border border-emerald-200">
                    Open
                  </Link>
                  <button onClick={() => deleteMatch(match.id)} className="text-gray-400 hover:text-red-500 px-2 py-1.5 rounded-lg text-sm">🗑️</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
